class Solution:
    def isTrionic(self, nums):
        n = len(nums)
        def inc(a, b):
            return all(nums[t] < nums[t + 1] for t in range(a, b))
        def dec(a, b):
            return all(nums[t] > nums[t + 1] for t in range(a, b))
        for p in range(1, n - 1):
            for q in range(p + 1, n - 1):
                if inc(0, p) and dec(p, q) and inc(q, n - 1):
                    return True
        return False

